    const n = nums.length;
    const sorted = [...nums].sort((a, b) => a - b);
    if (JSON.stringify(nums) === JSON.stringify(sorted)) {
        return 0;
    }

    let k = 0;
    for (let i = 0; i < n; i++) {
        if (nums[i] !== sorted[i]) {
            k |= nums[i] & sorted[i];
        }
    }

    // Verify if the found k allows sorting
    const parent = new Array(n).fill(0).map((_, i) => i);

    function find(u) {
        if (parent[u] !== u) {
            parent[u] = find(parent[u]);
        }
        return parent[u];
    }

    function union(u, v) {
        const rootU = find(u);
        const rootV = find(v);
        if (rootU !== rootV) {
            parent[rootV] = rootU;
        }
    }

    for (let i = 0; i < n; i++) {
        for (let j = i + 1; j < n; j++) {
            if ((nums[i] & nums[j]) === k) {
                union(i, j);
            }
        }
    }

    const groups = new Map();
    for (let i = 0; i < n; i++) {
        const root = find(i);
        if (!groups.has(root)) {
            groups.set(root, []);
        }
        groups.get(root).push(i);
    }

    for (const [_, indices] of groups) {
        const current = indices.map(i => nums[i]).sort((a, b) => a - b);
        const expected = indices.map(i => sorted[i]).sort((a, b) => a - b);
