                    let valid = true;
                    const tempParent = new Array(n).fill(0).map((_, i) => i);

                    function tempFind(u) {
                        if (tempParent[u] !== u) {
                            tempParent[u] = tempFind(tempParent[u]);
                        }
                        return tempParent[u];
                    }

                    function tempUnion(u, v) {
                        const rootU = tempFind(u);
                        const rootV = tempFind(v);
                        if (rootU !== rootV) {
                            tempParent[rootV] = rootU;
                        }
                    }

                    for (let i = 0; i < n; i++) {
                        for (let j = i + 1; j < n; j++) {
                            if ((nums[i] & nums[j]) === candidate) {
                                tempUnion(i, j);
                            }
                        }
                    }

                    const tempGroups = new Map();
                    for (let i = 0; i < n; i++) {
                        const root = tempFind(i);
                        if (!tempGroups.has(root)) {
                            tempGroups.set(root, []);
                        }
                        tempGroups.get(root).push(i);
