                        const tempCurrent = tempIndices.map(i => nums[i]).sort((a, b) => a - b);
                        const tempExpected = tempIndices.map(i => sorted[i]).sort((a, b) => a - b);
                        if (JSON.stringify(tempCurrent) !== JSON.stringify(tempExpected)) {
                            valid = false;
                            break;
                        }
                    }

                    if (valid) {
                        newK = candidate;
                    }
                }
            }
            return newK;
        }
    }

    return k;
